#include "moving_average.h"
#define MAX_WINDOW 64
static float _buf[MAX_WINDOW];
static uint8_t _size=10,_idx=0,_count=0;
static float _sum=0;
void mavg_setup(uint8_t w){_size=min(w,(uint8_t)MAX_WINDOW);_idx=0;_count=0;_sum=0;}
float mavg_add(float v){if(_count<_size){_buf[_idx]=v;_sum+=v;_count++;}else{_sum-=_buf[_idx];_buf[_idx]=v;_sum+=v;}_idx=(_idx+1)%_size;return _sum/_count;}
float mavg_get(){return _count>0?_sum/_count:0;}
void mavg_reset(){_idx=0;_count=0;_sum=0;}
